#include <stdio.h>
#include <stdlib.h>

// Structure to represent a job
typedef struct Job {
    int id;
    int deadline;
    int profit;
} Job;

// Comparison function for sorting jobs based on profit
int compareJobs(const void *a, const void *b) {
    Job *job1 = (Job *)a;
    Job *job2 = (Job *)b;
    return job2->profit - job1->profit;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        Job jobs[n];
        for (int i = 0; i < n; i++) {
            scanf("%d %d %d", &jobs[i].id, &jobs[i].deadline, &jobs[i].profit);
        }
        qsort(jobs, n, sizeof(Job), compareJobs);
        int scheduledJobs[n];
        for (int i = 0; i < n; i++) {
            scheduledJobs[i] = 0;
        }
        int totalProfit = 0;
        for (int i = 0; i < n; i++) {
            for (int j = jobs[i].deadline - 1; j >= 0; j--) {
                if (scheduledJobs[j] == 0) {
                    scheduledJobs[j] = jobs[i].id;
                    totalProfit += jobs[i].profit;
                    break;
                }
            }
        }
        for (int i = 0; i < n; i++) {
            if (scheduledJobs[i] != 0) {
                printf("%d ", scheduledJobs[i]);
            }
        }
        printf("\n%d\n", totalProfit);
    }
    return 0;
}

