import java.util.Arrays;
import java.util.Scanner;

public class Main {
    // Structure to represent a job
    static class Job {
        int id;
        int deadline;
        int profit;

        Job(int id, int deadline, int profit) {
            this.id = id;
            this.deadline = deadline;
            this.profit = profit;
        }
    }

    // Comparison function for sorting jobs based on profit
    static class JobComparator implements java.util.Comparator<Job> {
        public int compare(Job a, Job b) {
            return b.profit - a.profit;
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            Job[] jobs = new Job[n];
            for (int i = 0; i < n; i++) {
                jobs[i] = new Job(sc.nextInt(), sc.nextInt(), sc.nextInt());
            }
            Arrays.sort(jobs, new JobComparator());
            int[] scheduledJobs = new int[n];
            for (int i = 0; i < n; i++) {
                scheduledJobs[i] = 0;
            }
            int totalProfit = 0;
            for (int i = 0; i < n; i++) {
                for (int j = jobs[i].deadline - 1; j >= 0; j--) {
                    if (scheduledJobs[j] == 0) {
                        scheduledJobs[j] = jobs[i].id;
                        totalProfit += jobs[i].profit;
                        break;
                    }
                }
            }
            for (int i = 0; i < n; i++) {
                if (scheduledJobs[i] != 0) {
                    System.out.print(scheduledJobs[i] + " ");
                }
            }
            System.out.println(totalProfit);
        }
    }
}

