import sys

# Structure to represent a job
class Job:
    def __init__(self, id, deadline, profit):
        self.id = id
        self.deadline = deadline
        self.profit = profit

# Comparison function for sorting jobs based on profit
def compareJobs(a, b):
    return b.profit - a.profit

# Input jobs
T = int(input())
while T > 0:
    n = int(input())
    jobs = []
    for _ in range(n):
        id, deadline, profit = map(int, input().split())
        jobs.append(Job(id, deadline, profit))
    jobs.sort(key=lambda x: x.profit, reverse=True)
    scheduledJobs = [0] * n
    totalProfit = 0
    for i in range(n):
        for j in range(jobs[i].deadline - 1, -1, -1):
            if scheduledJobs[j] == 0:
                scheduledJobs[j] = jobs[i].id
                totalProfit += jobs[i].profit
                break
    for i in range(n):
        if scheduledJobs[i] != 0:
            print(scheduledJobs[i], end=" ")
    print(totalProfit)
    T -= 1

